using Microsoft.ML.Data;

namespace ChurnPredictor.Models;

public class ChurnInput
{
    [LoadColumn(0)]
    public float Age { get; set; }

    [LoadColumn(1)]
    public float Income { get; set; }

    [LoadColumn(2)]
    public string Region { get; set; } = string.Empty;

    [LoadColumn(3)]
    public float PurchaseHistory { get; set; }

    [LoadColumn(4)]
    public string Churned { get; set; } = string.Empty;
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }

    public float Probability { get; set; }

    public float Score { get; set; }
}

using Microsoft.ML;
using ChurnPredictor.Models;

namespace ChurnPredictor.Services;

public class ChurnModelTrainer
{
    private readonly ILogger<ChurnModelTrainer> _logger;

    public ChurnModelTrainer(ILogger<ChurnModelTrainer> logger)
    {
        _logger = logger;
    }

    public record TrainingMetrics(double AUC, double F1, double Accuracy);

    public TrainingMetrics Train(string csvPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<ChurnInput>(
            csvPath, hasHeader: true, separatorChar: ',');

        var lookupData = new[]
        {
            new { Key = "Yes", Value = true },
            new { Key = "No", Value = false }
        };
        var lookupView = mlContext.Data.LoadFromEnumerable(lookupData);

        var pipeline = mlContext.Transforms.Conversion.MapValue(
                "Label", lookupView, lookupView.Schema["Key"], lookupView.Schema["Value"], "Churned")
            .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
            .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.BinaryClassification.Evaluate(predictions);

        _logger.LogInformation("AUC: {AUC:F4}", metrics.AreaUnderRocCurve);
        _logger.LogInformation("F1: {F1:F4}", metrics.F1Score);
        _logger.LogInformation("Accuracy: {Accuracy:F4}", metrics.Accuracy);

        var dir = Path.GetDirectoryName(modelPath);
        if (!string.IsNullOrEmpty(dir))
            Directory.CreateDirectory(dir);

        mlContext.Model.Save(model, data.Schema, modelPath);
        _logger.LogInformation("Model saved to {Path}", modelPath);

        return new TrainingMetrics(metrics.AreaUnderRocCurve, metrics.F1Score, metrics.Accuracy);
    }
}

