using Microsoft.Extensions.ML;
using ChurnPredictor.Models;
using ChurnPredictor.Services;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddSingleton<ChurnModelTrainer>();

var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn-model.zip");

// Train the model at startup if it doesn't already exist
using (var sp = builder.Services.BuildServiceProvider())
{
    var trainer = sp.GetRequiredService<ChurnModelTrainer>();
    var csvPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
    trainer.Train(csvPath, modelPath);
}

builder.Services.AddPredictionEnginePool<ChurnInput, ChurnPrediction>()
    .FromFile(modelPath: modelPath, watchForChanges: true);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API");

app.MapGet("/train", (ChurnModelTrainer trainer, IWebHostEnvironment env) =>
{
    var csvPath = Path.Combine(env.ContentRootPath, "Data", "customers.csv");
    var savePath = Path.Combine(env.ContentRootPath, "Data", "churn-model.zip");
    var metrics = trainer.Train(csvPath, savePath);
    return Results.Ok(new { metrics.AUC, metrics.F1, metrics.Accuracy });
});

app.MapPost("/predict", (ChurnInput input, PredictionEnginePool<ChurnInput, ChurnPrediction> pool) =>
{
    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        prediction.PredictedLabel,
        prediction.Probability,
        prediction.Score
    });
});

app.Run();

