 var csvPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");

 // Train the model at startup so the pool has a model file to load
 var startupTrainer = new ChurnModelTrainer(
     LoggerFactory.Create(b => b.AddConsole()).CreateLogger<ChurnModelTrainer>());
